const fs = require('fs');
const path = require('path');

class ProblemsService {
  constructor() {
    this.problemsFilePath = path.resolve(__dirname, '../../data/problems.json');
    this.problemsData = null;
  }

  async loadProblemsData() {
    if (!this.problemsData) {
      const raw = await fs.promises.readFile(this.problemsFilePath, 'utf8');
      this.problemsData = JSON.parse(raw);
    }
    return this.problemsData;
  }

  async getProblemById(problemId) {
    const problems = await this.loadProblemsData();
    return problems.find(p => p.id === problemId);
  }

  async getProblemDetails(problemId) {
    const problem = await this.getProblemById(problemId);
    if (!problem) {
      const error = new Error('Problem not found');
      error.status = 404;
      throw error;
    }

    // Aggregate component statistics
    const componentStats = {
      languages: {},
      statusCounts: {},
      maxPoints: 0,
    };

    if (problem.components && Array.isArray(problem.components)) {
      for (const comp of problem.components) {
        // Aggregate languages counts
        if (comp.languages && Array.isArray(comp.languages)) {
          for (const lang of comp.languages) {
            componentStats.languages[lang] = (componentStats.languages[lang] || 0) + 1;
          }
        }

        // Aggregate status counts
        if (comp.status) {
          componentStats.statusCounts[comp.status] = (componentStats.statusCounts[comp.status] || 0) + 1;
        }

        // Track max points
        if (typeof comp.points === 'number' && comp.points > componentStats.maxPoints) {
          componentStats.maxPoints = comp.points;
        }
      }
    }

    return {
      ...problem,
      componentStats,
    };
  }
}

module.exports = new ProblemsService();
